import dbConnect from "@/db";
import { Base, Colorant, Formula } from "@/db/schema";
import { ensureSeed } from "@/db/seed";
import { sanitizeText } from "@/lib/sanitize";

export const dynamic = "force-dynamic";

interface ItemPayload {
  colorantCode?: unknown;
  mlPerLiter?: unknown;
}

interface FormulaPayload {
  name?: unknown;
  baseCode?: unknown;
  notes?: unknown;
  items?: unknown;
}

export async function GET(request: Request) {
  try {
    await dbConnect();
    await ensureSeed();
    const { searchParams } = new URL(request.url);
    const query = sanitizeText(searchParams.get("q") ?? "", 80);

    let filter = {};
    if (query) {
      filter = { name: { $regex: query, $options: "i" } };
    }

    const rows = await Formula.find(filter)
      .sort({ isPreset: 1, createdAt: -1 })
      .limit(100)
      .lean();

    const colorantRows = await Colorant.find({}).lean();
    const colorantNameMap = new Map(colorantRows.map((c: any) => [c.code, c.name]));

    const result = rows.map((row: any) => {
      const items = (row.items || []).map((item: any) => ({
        colorantCode: item.colorantCode,
        mlPerLiter: item.mlPerLiter,
        colorantName: colorantNameMap.get(item.colorantCode) ?? item.colorantCode,
      }));

      items.sort((a: any, b: any) => b.mlPerLiter - a.mlPerLiter);

      return {
        id: row._id.toString(),
        name: row.name,
        baseCode: row.baseCode,
        notes: row.notes,
        isPreset: row.isPreset,
        createdAt: row.createdAt ? row.createdAt.toISOString() : new Date().toISOString(),
        items,
      };
    });

    return Response.json({ formulas: result });
  } catch (error) {
    console.error("[formulas] GET failed", error);
    return Response.json(
      { error: "Saved formulas could not be loaded. Check the connection and retry." },
      { status: 500 },
    );
  }
}

export async function POST(request: Request) {
  try {
    await dbConnect();
    await ensureSeed();
    let body: FormulaPayload;
    try {
      body = (await request.json()) as FormulaPayload;
    } catch {
      return Response.json({ error: "Request body is not valid JSON." }, { status: 400 });
    }

    const name = sanitizeText(typeof body.name === "string" ? body.name : "", 60);
    if (name.length < 2) {
      return Response.json(
        { error: "Formula name is required (minimum 2 characters).", field: "name" },
        { status: 400 },
      );
    }

    const baseCode = sanitizeText(typeof body.baseCode === "string" ? body.baseCode : "", 16);
    const baseRow = await Base.findOne({ code: baseCode }).lean();
    if (!baseRow) {
      return Response.json(
        { error: "Select a valid base paint.", field: "base" },
        { status: 400 },
      );
    }

    const rawItems = Array.isArray(body.items) ? (body.items as ItemPayload[]) : [];
    if (rawItems.length === 0 || rawItems.length > 12) {
      return Response.json(
        { error: "A formula needs between 1 and 12 colorant rows." },
        { status: 400 },
      );
    }

    const validColorants = await Colorant.find({}).lean();
    const known = new Set(validColorants.map((c: any) => c.code));
    const seen = new Set<string>();
    const cleanedItems: Array<{ colorantCode: string; mlPerLiter: number }> = [];

    for (const item of rawItems) {
      const code = sanitizeText(typeof item.colorantCode === "string" ? item.colorantCode : "", 16);
      const rate = typeof item.mlPerLiter === "number" ? item.mlPerLiter : Number(item.mlPerLiter);
      if (!known.has(code)) {
        return Response.json(
          { error: `Unknown colorant "${code || "(empty)"}".` },
          { status: 400 },
        );
      }
      if (seen.has(code)) {
        return Response.json(
          { error: `Duplicate colorant row for ${code}.` },
          { status: 400 },
        );
      }
      if (!Number.isFinite(rate) || rate <= 0 || rate > 600) {
        return Response.json(
          { error: `Rate for ${code} must be between 0 and 600 ml/L.` },
          { status: 400 },
        );
      }
      seen.add(code);
      cleanedItems.push({ colorantCode: code, mlPerLiter: Math.round(rate * 100) / 100 });
    }

    const notes = sanitizeText(typeof body.notes === "string" ? body.notes : "", 240);

    const inserted = await Formula.create({
      name,
      baseCode,
      notes: notes.length > 0 ? notes : null,
      isPreset: false,
      items: cleanedItems,
    });

    const colorantNameMap = new Map(validColorants.map((c: any) => [c.code, c.name]));
    
    return Response.json(
      {
        formula: {
          id: inserted._id.toString(),
          name: inserted.name,
          baseCode: inserted.baseCode,
          notes: inserted.notes,
          isPreset: inserted.isPreset,
          createdAt: inserted.createdAt.toISOString(),
          items: inserted.items.map((i: any) => ({
            colorantCode: i.colorantCode,
            mlPerLiter: i.mlPerLiter,
            colorantName: colorantNameMap.get(i.colorantCode) ?? i.colorantCode,
          })),
        },
      },
      { status: 201 },
    );
  } catch (error) {
    console.error("[formulas] POST failed", error);
    return Response.json(
      { error: "The formula could not be saved. Your work is preserved — retry when ready." },
      { status: 500 },
    );
  }
}
